target.script:

try {
  var igTemp = project.getProperty("ig.temp");
  var igSourceXml = project.getProperty("onGenerate.ig.source") + "xml";
  var xmlFile = new java.io.File(igSourceXml);
  if (xmlFile.exists()) {
    var dbf = javax.xml.parsers.DocumentBuilderFactory.newInstance();
    dbf.setNamespaceAware(true);
    var db = dbf.newDocumentBuilder();
    var doc = db.parse(xmlFile);
    var params = doc.getElementsByTagNameNS("http://hl7.org/fhir", "parameter");
    for (var i = 0; i < params.getLength(); i++) {
      var param = params.item(i);
      var codeElems = param.getElementsByTagNameNS("http://hl7.org/fhir", "code");
      var valueElems = param.getElementsByTagNameNS("http://hl7.org/fhir", "value");
      if (codeElems.getLength() > 0 && valueElems.getLength() > 0) {
        var code = codeElems.item(0).getAttribute("value");
        if (code === "i18n-default-lang") {
          var lang = valueElems.item(0).getAttribute("value");
          var dir = new java.io.File(igTemp + "/_includes/" + lang);
          dir.mkdirs();
        }
      }
    }
  }
} catch(e) {
  project.log("ANS: error creating lang include dirs: " + e);
}
